// =============================================================
// URL helpers
// =============================================================
function detectUrlType(url) {
  if (!url) return 'web';
  const u = url.toLowerCase();
  if (u.includes('instagram.com') || u.includes('instagr.am')) return 'instagram';
  if (u.includes('maps.google') || u.includes('goo.gl/maps') || u.includes('maps.app.goo.gl') || u.includes('google.com/maps')) return 'maps';
  return 'web';
}

function urlIcon(type, size = 14) {
  if (type === 'instagram') return <Instagram size={size} />;
  if (type === 'maps')      return <MapPin size={size} />;
  return <LinkIcon size={size} />;
}

function formatDate(iso) {
  if (!iso) return null;
  try {
    const d = new Date(iso);
    return d.toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' });
  } catch (e) {
    return iso;
  }
}

