// === Chapter ===
function Chapter({ ch, index, total, isOpen, onToggle, isFav, onFav, chapterRef }) {
  const visibleMessages = isOpen ? ch.messages : ch.messages.slice(0, Math.min(2, ch.messages.length));

  return (
    <article ref={chapterRef} style={{
      padding: '50px 0',
      borderTop: index === 0 ? 'none' : '1px solid rgba(28, 26, 23, 0.08)',
    }}>
      <header style={{ marginBottom: '32px' }}>
        <div style={{
          display: 'flex', alignItems: 'baseline', justifyContent: 'space-between',
          marginBottom: '20px', gap: '16px'
        }}>
          <div>
            <div style={{
              fontSize: '10px', letterSpacing: '0.28em',
              color: '#A8503D', fontWeight: 500, marginBottom: '8px'
            }}>
              {String(index + 1).padStart(2, '0')} · {ch.weekday}
            </div>
            <div style={{
              fontFamily: "'Fraunces', serif", fontSize: '13px',
              fontStyle: 'italic', color: '#6B6963', fontWeight: 300,
            }}>
              {ch.date}{ch.time ? ` · ${ch.time}` : ''}
            </div>
          </div>
          <button onClick={onFav} aria-label={isFav ? 'Retirer des favoris' : 'Ajouter aux favoris'}
            style={{
              background: 'none', border: 'none', cursor: 'pointer',
              padding: '4px', color: isFav ? '#A8503D' : '#A39C92',
              transition: 'color 0.2s', display: 'flex', alignItems: 'center'
            }}>
            {isFav ? <BookmarkCheck size={16}/> : <Bookmark size={16}/>}
          </button>
        </div>
        <h2 style={{
          fontFamily: "'Fraunces', serif",
          fontSize: 'clamp(28px, 5.5vw, 40px)',
          fontWeight: 400, lineHeight: 1.1, letterSpacing: '-0.015em',
          margin: '0 0 22px', color: '#1C1A17',
          fontVariationSettings: "'opsz' 144, 'SOFT' 50",
        }}>
          {ch.title}
        </h2>
        <p style={{
          fontFamily: "'Fraunces', serif", fontSize: '17px',
          lineHeight: 1.55, color: '#3D3A35', margin: 0,
          fontWeight: 300, fontVariationSettings: "'opsz' 12",
        }}>
          {ch.headline}
        </p>
      </header>

      {ch.image && (
        <figure style={{ margin: '0 -8px 32px', position: 'relative' }}>
          <div style={{
            background: `url(${ch.image}) center/cover`,
            aspectRatio: '1 / 1', borderRadius: '4px',
            position: 'relative', overflow: 'hidden'
          }}>
            <div style={{
              position: 'absolute', top: '14px', left: '14px',
              background: 'rgba(255,255,255,0.9)', backdropFilter: 'blur(8px)',
              borderRadius: '999px', padding: '6px 12px',
              fontSize: '10px', letterSpacing: '0.2em',
              color: '#A8503D', fontWeight: 600,
              display: 'flex', alignItems: 'center', gap: '6px'
            }}>
              <Heart size={10} fill="#A8503D" stroke="#A8503D"/> A LIKÉ
            </div>
          </div>
          {ch.imageCaption && (
            <figcaption style={{
              marginTop: '12px', padding: '0 8px',
              fontSize: '12px', fontStyle: 'italic',
              fontFamily: "'Fraunces', serif",
              color: '#A39C92', textAlign: 'center'
            }}>
              {ch.imageCaption}
            </figcaption>
          )}
        </figure>
      )}

      <div style={{
        background: '#FFFFFF', borderRadius: '4px',
        padding: '8px 0', border: '1px solid rgba(28, 26, 23, 0.06)'
      }}>
        {visibleMessages.map((m, i) => (
          <Message key={i} m={m} isLast={i === visibleMessages.length - 1} />
        ))}
      </div>

      {ch.messages.length > 2 && (
        <button onClick={onToggle} style={{
          marginTop: '20px', background: 'none', border: 'none',
          color: '#A8503D', fontFamily: "'Geist', sans-serif",
          fontSize: '11px', letterSpacing: '0.18em', fontWeight: 500,
          cursor: 'pointer', padding: '12px 0',
          display: 'flex', alignItems: 'center', gap: '8px'
        }}>
          {isOpen ? (<>REPLIER <ChevronUp size={14}/></>)
                  : (<>LIRE LES {ch.messages.length} MESSAGES <ChevronDown size={14}/></>)}
        </button>
      )}
    </article>
  );
}

// === Message ===
function Message({ m, isLast }) {
  const speakers = {
    A: { name: 'Arthur', color: '#1C1A17' },
    L: { name: 'Laurie', color: '#A8503D' },
    S: { name: null, color: '#A39C92' }
  };
  const sp = speakers[m.s];

  if (m.s === 'S') {
    return (
      <div style={{
        padding: '24px 24px', textAlign: 'center',
        fontSize: '11px', letterSpacing: '0.2em',
        color: '#A39C92', fontFamily: "'Geist', sans-serif",
        fontWeight: 500, display: 'flex',
        alignItems: 'center', justifyContent: 'center', gap: '8px'
      }}>
        <Heart size={11} fill="#A8503D" stroke="#A8503D" />
        {m.t.toUpperCase()}
      </div>
    );
  }
  return (
    <div style={{
      padding: '14px 22px',
      borderBottom: isLast ? 'none' : '1px solid rgba(28, 26, 23, 0.04)',
    }}>
      <div style={{
        fontSize: '10px', letterSpacing: '0.22em',
        fontWeight: 600, color: sp.color, marginBottom: '6px'
      }}>
        {sp.name.toUpperCase()}
      </div>
      <div style={{
        fontSize: '15px', lineHeight: 1.55, color: '#1C1A17',
        fontFamily: "'Fraunces', serif", fontWeight: 300,
        fontVariationSettings: "'opsz' 14",
      }}>
        {m.t}
      </div>
    </div>
  );
}

// =============================================================
// VIEW · CARNETS
// =============================================================
function CarnetsView() {
  const [activeCarnet, setActiveCarnet] = useState('restaurants');
  const [entries, setEntries] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [editing, setEditing] = useState(null); // entry being edited (or null)
  const [adding, setAdding] = useState(false);

  // Load entries from storage on mount; seed if empty
  useEffect(() => {
    (async () => {
      try {
        const r = await window.storage.get('carnet-entries');
        if (r && r.value) {
          setEntries(JSON.parse(r.value));
        } else {
          // First time: seed with conversation places
          setEntries(SEED_ENTRIES);
          await window.storage.set('carnet-entries', JSON.stringify(SEED_ENTRIES));
        }
      } catch(e) {
        // No existing data: seed
        setEntries(SEED_ENTRIES);
        try { await window.storage.set('carnet-entries', JSON.stringify(SEED_ENTRIES)); }
        catch(err) { console.error(err); }
      }
      setLoaded(true);
    })();
  }, []);

  const persist = async (next) => {
    setEntries(next);
    try { await window.storage.set('carnet-entries', JSON.stringify(next)); }
    catch(e) { console.error(e); }
  };

  const addEntry = async (entry) => {
    const newEntry = { ...entry, id: 'e-' + Date.now(), createdAt: Date.now() };
    await persist([newEntry, ...entries]);
    setAdding(false);
  };
  const updateEntry = async (id, patch) => {
    await persist(entries.map(e => e.id === id ? { ...e, ...patch } : e));
    setEditing(null);
  };
  const removeEntry = async (id) => {
    await persist(entries.filter(e => e.id !== id));
  };

  const filtered = entries.filter(e => e.carnet === activeCarnet);
  const counts = CARNETS.reduce((acc, c) => {
    acc[c.id] = entries.filter(e => e.carnet === c.id).length;
    return acc;
  }, {});

  const carnetMeta = CARNETS.find(c => c.id === activeCarnet);

  return (
    <>
      {/* Header */}
      <section style={{
        padding: '60px 24px 30px', textAlign: 'center',
        maxWidth: '720px', margin: '0 auto'
      }}>
        <div style={{
          fontSize: '11px', letterSpacing: '0.32em',
          color: '#A8503D', marginBottom: '24px', fontWeight: 500
        }}>
          NOS LIEUX, NOS PROJETS
        </div>
        <h1 style={{
          fontFamily: "'Fraunces', serif",
          fontSize: 'clamp(40px, 10vw, 64px)',
          fontWeight: 300, lineHeight: 0.95,
          fontVariationSettings: "'opsz' 144, 'SOFT' 100",
          letterSpacing: '-0.02em', margin: 0, fontStyle: 'italic'
        }}>
          Les Carnets
        </h1>
        <p style={{
          marginTop: '24px', fontSize: '14px', color: '#6B6963',
          lineHeight: 1.7, maxWidth: '440px', margin: '24px auto 0',
          fontFamily: "'Fraunces', serif", fontStyle: 'italic',
          fontWeight: 300
        }}>
          Ce qui nous a marqués, ce qu'on veut faire, ce qu'on a aimé.
        </p>
      </section>

      {/* Carnet tabs */}
      <div style={{
        position: 'sticky', top: '52px', zIndex: 30,
        background: 'rgba(250, 248, 244, 0.92)',
        backdropFilter: 'blur(12px)',
        padding: '12px 0',
        borderBottom: '1px solid rgba(28, 26, 23, 0.06)',
      }}>
        <div style={{
          display: 'flex', gap: '8px', overflowX: 'auto',
          padding: '0 24px',
          scrollbarWidth: 'none',
          maxWidth: '720px', margin: '0 auto'
        }}>
          {CARNETS.map(c => (
            <CarnetTab key={c.id} carnet={c} count={counts[c.id]}
              active={activeCarnet === c.id}
              onClick={() => setActiveCarnet(c.id)} />
          ))}
        </div>
      </div>

      {/* Entries */}
      <main style={{
        maxWidth: '720px', margin: '0 auto',
        padding: '32px 24px 120px'
      }}>
        {!loaded && (
          <div style={{ textAlign: 'center', color: '#A39C92', padding: '40px', fontSize: '13px' }}>
            Chargement…
          </div>
        )}

        {loaded && filtered.length === 0 && (
          <EmptyState carnet={carnetMeta} onAdd={() => setAdding(true)} />
        )}

        {loaded && filtered.length > 0 && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: '16px'
          }}>
            {filtered.map(entry => (
              <EntryCard key={entry.id} entry={entry}
                onEdit={() => setEditing(entry)}
                onDelete={() => removeEntry(entry.id)} />
            ))}
          </div>
        )}
      </main>

      {/* Floating Add button */}
      <button
        onClick={() => setAdding(true)}
        aria-label="Ajouter une entrée"
        style={{
          position: 'fixed', bottom: '28px', right: '28px',
          width: '56px', height: '56px', borderRadius: '50%',
          background: '#1C1A17', color: '#FAF8F4',
          border: 'none', cursor: 'pointer',
          boxShadow: '0 8px 24px rgba(28, 26, 23, 0.18)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          zIndex: 40, transition: 'transform 0.2s'
        }}
        onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.06)'}
        onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}>
        <Plus size={22} strokeWidth={2.2}/>
      </button>

      {/* Add / edit modal */}
      {(adding || editing) && (
        <EntryModal
          initial={editing || { carnet: activeCarnet }}
          onCancel={() => { setAdding(false); setEditing(null); }}
          onSave={(data) => editing
            ? updateEntry(editing.id, data)
            : addEntry(data)
          }
          isEdit={!!editing}
        />
      )}
    </>
  );
}

function CarnetTab({ carnet, count, active, onClick }) {
  return (
    <button onClick={onClick} style={{
      flex: '0 0 auto',
      padding: '10px 16px',
      borderRadius: '4px',
      background: active ? '#1C1A17' : 'transparent',
      color: active ? '#FAF8F4' : '#1C1A17',
      border: active ? 'none' : '1px solid rgba(28, 26, 23, 0.12)',
      cursor: 'pointer',
      fontFamily: "'Geist', sans-serif",
      fontSize: '12px', fontWeight: 500,
      letterSpacing: '0.06em',
      display: 'flex', alignItems: 'baseline', gap: '8px',
      transition: 'all 0.2s'
    }}>
      <span>{carnet.label}</span>
      <span style={{
        fontSize: '10px',
        opacity: 0.55,
        fontVariantNumeric: 'tabular-nums'
      }}>
        {count}
      </span>
    </button>
  );
}

function EmptyState({ carnet, onAdd }) {
  return (
    <div style={{
      textAlign: 'center', padding: '70px 20px',
      maxWidth: '420px', margin: '0 auto'
    }}>
      <div style={{
        fontFamily: "'Fraunces', serif", fontStyle: 'italic',
        fontSize: '28px', fontWeight: 300, color: '#1C1A17',
        marginBottom: '16px',
        fontVariationSettings: "'opsz' 144, 'SOFT' 100",
      }}>
        Carnet vierge.
      </div>
      <p style={{
        fontSize: '14px', color: '#6B6963', lineHeight: 1.6,
        marginBottom: '28px'
      }}>
        Aucune entrée pour <strong style={{color: '#1C1A17'}}>{carnet.label}</strong> pour le moment.
        Ajoute la première — un restaurant testé, un endroit à voir, une idée à garder.
      </p>
      <button onClick={onAdd} style={{
        padding: '12px 22px', background: '#1C1A17',
        color: '#FAF8F4', border: 'none', borderRadius: '4px',
        cursor: 'pointer', fontSize: '12px', letterSpacing: '0.18em',
        fontWeight: 500, fontFamily: "'Geist', sans-serif",
        textTransform: 'uppercase'
      }}>
        Première entrée
      </button>
    </div>
  );
}

function EntryCard({ entry, onEdit, onDelete }) {
  const [showActions, setShowActions] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const type = detectUrlType(entry.url);

  const typeLabel = { instagram: 'Instagram', maps: 'Google Maps', web: 'Lien' }[type];

  return (
    <article
      onMouseEnter={() => setShowActions(true)}
      onMouseLeave={() => { setShowActions(false); setConfirmDelete(false); }}
      style={{
        background: '#FFFFFF',
        border: '1px solid rgba(28, 26, 23, 0.06)',
        borderRadius: '4px',
        padding: '20px',
        position: 'relative',
        display: 'flex',
        flexDirection: 'column',
        minHeight: '160px',
      }}>

      {/* Type badge */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: '6px',
        fontSize: '10px', letterSpacing: '0.18em',
        color: '#A8503D', fontWeight: 500,
        marginBottom: '12px'
      }}>
        {urlIcon(type, 11)}
        {typeLabel.toUpperCase()}
      </div>

      {/* Title */}
      <h3 style={{
        fontFamily: "'Fraunces', serif",
        fontSize: '22px', fontWeight: 400, lineHeight: 1.2,
        margin: '0 0 10px', color: '#1C1A17',
        fontVariationSettings: "'opsz' 144",
        letterSpacing: '-0.01em'
      }}>
        {entry.title}
      </h3>

      {/* Notes */}
      {entry.notes && (
        <p style={{
          fontSize: '13px', lineHeight: 1.55,
          color: '#6B6963', margin: '0 0 14px',
          fontFamily: "'Fraunces', serif", fontWeight: 300,
          fontStyle: 'italic',
        }}>
          {entry.notes}
        </p>
      )}

      <div style={{ marginTop: 'auto', paddingTop: '8px' }}>
        {/* Date */}
        {entry.date && (
          <div style={{
            fontSize: '11px', letterSpacing: '0.1em',
            color: '#A39C92', marginBottom: '10px',
            display: 'flex', alignItems: 'center', gap: '6px'
          }}>
            <Calendar size={11}/>
            {formatDate(entry.date)}
          </div>
        )}

        {/* Open link */}
        {entry.url && (
          <a href={entry.url} target="_blank" rel="noopener noreferrer"
            style={{
              fontSize: '11px', letterSpacing: '0.18em',
              color: '#1C1A17', fontWeight: 500,
              textDecoration: 'none', textTransform: 'uppercase',
              display: 'inline-flex', alignItems: 'center', gap: '6px',
              borderBottom: '1px solid rgba(28, 26, 23, 0.4)',
              paddingBottom: '2px'
            }}>
            Ouvrir <ExternalLink size={11}/>
          </a>
        )}
      </div>

      {/* Actions */}
      {(showActions || confirmDelete) && (
        <div style={{
          position: 'absolute', top: '12px', right: '12px',
          display: 'flex', gap: '4px'
        }}>
          {!confirmDelete && (
            <>
              <IconButton onClick={onEdit} title="Modifier"><Edit3 size={13}/></IconButton>
              <IconButton onClick={() => setConfirmDelete(true)} title="Supprimer" danger><Trash2 size={13}/></IconButton>
            </>
          )}
          {confirmDelete && (
            <>
              <IconButton onClick={onDelete} title="Confirmer suppression" danger><Check size={13}/></IconButton>
              <IconButton onClick={() => setConfirmDelete(false)} title="Annuler"><X size={13}/></IconButton>
            </>
          )}
        </div>
      )}
    </article>
  );
}

function IconButton({ onClick, title, danger, children }) {
  return (
    <button onClick={onClick} title={title}
      style={{
        width: '28px', height: '28px',
        borderRadius: '4px',
        background: danger ? 'rgba(168, 80, 61, 0.1)' : 'rgba(28, 26, 23, 0.05)',
        color: danger ? '#A8503D' : '#1C1A17',
        border: 'none', cursor: 'pointer',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        transition: 'background 0.15s'
      }}>
      {children}
    </button>
  );
}

// === Add / Edit modal ===
function EntryModal({ initial, onCancel, onSave, isEdit }) {
  const [title, setTitle] = useState(initial.title || '');
  const [url, setUrl] = useState(initial.url || '');
  const [notes, setNotes] = useState(initial.notes || '');
  const [date, setDate] = useState(initial.date || '');
  const [carnet, setCarnet] = useState(initial.carnet || 'restaurants');

  const urlType = detectUrlType(url);
  const typeLabel = { instagram: 'Instagram', maps: 'Google Maps', web: 'Lien web' }[urlType];

  const canSave = title.trim().length > 0;

  const handleSave = () => {
    if (!canSave) return;
    onSave({
      title: title.trim(),
      url: url.trim(),
      notes: notes.trim(),
      date: date || null,
      carnet,
    });
  };

  return (
    <div style={{
      position: 'fixed', inset: 0,
      background: 'rgba(28, 26, 23, 0.45)',
      backdropFilter: 'blur(4px)',
      zIndex: 100,
      display: 'flex', alignItems: 'flex-end', justifyContent: 'center',
    }} onClick={onCancel}>

      <div onClick={(e) => e.stopPropagation()} style={{
        background: '#FAF8F4',
        width: '100%', maxWidth: '560px',
        borderTopLeftRadius: '12px',
        borderTopRightRadius: '12px',
        padding: '28px 24px 32px',
        maxHeight: '92vh', overflowY: 'auto',
      }}>
        {/* Handle */}
        <div style={{
          width: '36px', height: '4px',
          background: 'rgba(28, 26, 23, 0.15)',
          borderRadius: '2px',
          margin: '0 auto 24px'
        }}/>

        <div style={{
          display: 'flex', justifyContent: 'space-between',
          alignItems: 'center', marginBottom: '24px'
        }}>
          <h2 style={{
            fontFamily: "'Fraunces', serif", fontStyle: 'italic',
            fontSize: '26px', fontWeight: 300, margin: 0,
            color: '#1C1A17',
            fontVariationSettings: "'opsz' 144, 'SOFT' 100",
          }}>
            {isEdit ? 'Modifier' : 'Nouvelle entrée'}
          </h2>
          <button onClick={onCancel} style={{
            background: 'transparent', border: 'none',
            cursor: 'pointer', padding: '8px',
            color: '#6B6963',
          }}>
            <X size={20}/>
          </button>
        </div>

        {/* Title */}
        <Field label="Titre">
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Mano Mano, Ischia, Sainte-Sophie…"
            style={inputStyle}
            autoFocus
          />
        </Field>

        {/* URL */}
        <Field label="Lien (Instagram, Google Maps, ou autre)">
          <input
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            placeholder="https://…"
            style={inputStyle}
          />
          {url && (
            <div style={{
              marginTop: '8px', fontSize: '11px',
              letterSpacing: '0.14em', color: '#A8503D',
              display: 'flex', alignItems: 'center', gap: '6px'
            }}>
              {urlIcon(urlType, 11)} DÉTECTÉ : {typeLabel.toUpperCase()}
            </div>
          )}
        </Field>

        {/* Carnet */}
        <Field label="Carnet">
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
            {CARNETS.map(c => (
              <button key={c.id} onClick={() => setCarnet(c.id)}
                style={{
                  padding: '8px 14px', borderRadius: '4px',
                  border: '1px solid',
                  borderColor: carnet === c.id ? '#1C1A17' : 'rgba(28, 26, 23, 0.15)',
                  background: carnet === c.id ? '#1C1A17' : 'transparent',
                  color: carnet === c.id ? '#FAF8F4' : '#1C1A17',
                  fontSize: '12px', cursor: 'pointer',
                  fontFamily: "'Geist', sans-serif",
                  letterSpacing: '0.04em',
                }}>
                {c.label}
              </button>
            ))}
          </div>
        </Field>

        {/* Notes */}
        <Field label="Notes (optionnel)">
          <textarea
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Premier rendez-vous, terrasse… "
            rows={3}
            style={{ ...inputStyle, resize: 'vertical', minHeight: '76px', fontFamily: "'Fraunces', serif", fontStyle: 'italic' }}
          />
        </Field>

        {/* Date */}
        <Field label="Date (optionnel)">
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            style={inputStyle}
          />
        </Field>

        <div style={{
          display: 'flex', gap: '10px', marginTop: '24px'
        }}>
          <button onClick={onCancel} style={{
            flex: 1, padding: '14px',
            background: 'transparent',
            border: '1px solid rgba(28, 26, 23, 0.2)',
            borderRadius: '4px', cursor: 'pointer',
            fontSize: '12px', letterSpacing: '0.16em',
            fontFamily: "'Geist', sans-serif",
            fontWeight: 500, textTransform: 'uppercase',
            color: '#1C1A17',
          }}>
            Annuler
          </button>
          <button onClick={handleSave} disabled={!canSave} style={{
            flex: 2, padding: '14px',
            background: canSave ? '#1C1A17' : 'rgba(28, 26, 23, 0.3)',
            color: '#FAF8F4', border: 'none',
            borderRadius: '4px',
            cursor: canSave ? 'pointer' : 'not-allowed',
            fontSize: '12px', letterSpacing: '0.16em',
            fontFamily: "'Geist', sans-serif",
            fontWeight: 500, textTransform: 'uppercase',
          }}>
            {isEdit ? 'Enregistrer' : 'Ajouter'}
          </button>
        </div>
      </div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ marginBottom: '18px' }}>
      <label style={{
        display: 'block', fontSize: '10px',
        letterSpacing: '0.22em', color: '#6B6963',
        textTransform: 'uppercase', fontWeight: 500,
        marginBottom: '8px',
        fontFamily: "'Geist', sans-serif"
      }}>
        {label}
      </label>
      {children}
    </div>
  );
}

const inputStyle = {
  width: '100%',
  padding: '12px 14px',
  border: '1px solid rgba(28, 26, 23, 0.12)',
  borderRadius: '4px',
  background: '#FFFFFF',
  fontSize: '15px',
  color: '#1C1A17',
  fontFamily: "'Geist', sans-serif",
  outline: 'none',
  boxSizing: 'border-box',
};
